import edu.ucr.cs.bdlab.beast._
import org.apache.spark.rdd.RDD

val expectedPartitions = 13
val builder = sc.generateSpatialData.numPartitions(expectedPartitions)

// Attempt to find a terminal method (e.g., point, box, polygon) to materialize the RDD
val methods = builder.getClass.getMethods
val terminalMethod = methods.find { m =>
  val name = m.getName.toLowerCase
  (name == "point" || name == "box" || name == "polygon" || name == "generatepoint") &&
    m.getParameterCount == 1 &&
    (m.getParameterTypes.head == classOf[Long] || m.getParameterTypes.head == classOf[Int])
}

if (terminalMethod.isDefined) {
  val m = terminalMethod.get
  val rdd = if (m.getParameterTypes.head == classOf[Int]) {
    m.invoke(builder, 100.asInstanceOf[AnyRef]).asInstanceOf[RDD[_]]
  } else {
    m.invoke(builder, 100L.asInstanceOf[AnyRef]).asInstanceOf[RDD[_]]
  }
  val actualPartitions = rdd.getNumPartitions
  assert(actualPartitions == expectedPartitions, s"Expected $expectedPartitions partitions, got $actualPartitions")
  println(s"__CHECK__ numPartitions $actualPartitions")
} else {
  // Fallback: verify the builder's internal state via reflection if terminal method is unknown
  var found = false
  var currentClass: Class[_] = builder.getClass
  while (currentClass != null && !found) {
    for (f <- currentClass.getDeclaredFields) {
      f.setAccessible(true)
      try {
        if (f.get(builder) == expectedPartitions) found = true
      } catch {
        case _: Throwable => // ignore inaccessible or incompatible fields
      }
    }
    currentClass = currentClass.getSuperclass
  }
  assert(found, s"Could not verify that numPartitions was set to $expectedPartitions via reflection.")
  println(s"__CHECK__ numPartitions $expectedPartitions")
}

