import edu.ucr.cs.bdlab.beast.util.ZipUtil
import java.util.zip.{ZipOutputStream, ZipFile, ZipEntry}
import java.io.{File, FileOutputStream}

val zipFile = new File(output_dir, "test_stored.zip")
val zipOut = new ZipOutputStream(new FileOutputStream(zipFile))

val testData = Array[Byte](10, 20, 30, 40, 50)

try {
  ZipUtil.putStoredFile(zipOut, "data.bin", testData)
} finally {
  zipOut.close()
}

val zf = new ZipFile(zipFile)
try {
  val entry = zf.getEntry("data.bin")
  assert(entry != null, "data.bin should exist in the zip archive")
  assert(entry.getMethod == ZipEntry.STORED, "data.bin should be stored without compression (STORED)")
  assert(entry.getSize == testData.length, "data.bin size should match the input byte array length")

  val is = zf.getInputStream(entry)
  val readData = new Array[Byte](testData.length)
  var offset = 0
  while (offset < readData.length) {
    val bytesRead = is.read(readData, offset, readData.length - offset)
    if (bytesRead == -1) throw new java.io.EOFException()
    offset += bytesRead
  }
  is.close()

  assert(readData.sameElements(testData), "Read data should exactly match the written byte array")

  println(s"__CHECK__ putStoredFile ${entry.getName}, size: ${entry.getSize}, method: ${entry.getMethod}")
} finally {
  zf.close()
}

