import org.locationtech.jts.geom.Envelope
import edu.ucr.cs.bdlab.beast.cg.Reprojector

// Create a source envelope in EPSG:4326 (WGS84)
// Coordinates: minX (longitude), maxX, minY (latitude), maxY
val sourceEnvelope = new Envelope(-124.0, -114.0, 32.0, 42.0)

// Reproject the envelope to EPSG:3857 (Web Mercator)
val targetEnvelope = Reprojector.reprojectEnvelope(sourceEnvelope, 4326, 3857)

// Verify the reprojection to Web Mercator meters
// -124.0 longitude is approximately -13.8 million meters in X
assert(targetEnvelope.getMinX < -13000000.0 && targetEnvelope.getMinX > -14000000.0, s"Unexpected minX: ${targetEnvelope.getMinX}")
// 32.0 latitude is approximately 3.7 million meters in Y
assert(targetEnvelope.getMinY > 3000000.0 && targetEnvelope.getMinY < 4000000.0, s"Unexpected minY: ${targetEnvelope.getMinY}")

// Reproject back to verify round-trip consistency
val backEnvelope = Reprojector.reprojectEnvelope(targetEnvelope, 3857, 4326)
assert(Math.abs(backEnvelope.getMinX - sourceEnvelope.getMinX) < 0.001, s"Round-trip minX failed: ${backEnvelope.getMinX}")
assert(Math.abs(backEnvelope.getMaxY - sourceEnvelope.getMaxY) < 0.001, s"Round-trip maxY failed: ${backEnvelope.getMaxY}")

println(s"__CHECK__ reprojectEnvelope ${targetEnvelope.toString}")

