import org.apache.hadoop.fs.{Path, FileUtil}
import org.locationtech.jts.geom.{Envelope, GeometryFactory, PrecisionModel}
import edu.ucr.cs.bdlab.raptor.RasterFileRDD

// Obtain the FileSystem and source path
val sourcePath = new Path(raster_tif)
val fs = sourcePath.getFileSystem(sc.hadoopConfiguration)

// Create a temporary directory in output_dir to hold the raster and its index safely
val testDir = new Path(output_dir, "select_files_test")
fs.mkdirs(testDir)

// Copy the raster to the new directory
val destPath = new Path(testDir, sourcePath.getName)
FileUtil.copy(fs, sourcePath, fs, destPath, false, sc.hadoopConfiguration)

val dir = testDir.toString
val indexPath = new Path(testDir, "_index.csv").toString

// Build the index to enable spatial pruning
RasterFileRDD.buildIndex(sc, dir, indexPath)

// Create a massive query range that is guaranteed to overlap the raster regardless of its CRS
val geometryFactory = new GeometryFactory(new PrecisionModel(PrecisionModel.FLOATING_SINGLE), 4326)
val queryRange = geometryFactory.toGeometry(new Envelope(-1e10, 1e10, -1e10, 1e10))

// Call selectFiles to prune and find overlapping files
val matchingFiles = RasterFileRDD.selectFiles(fs, dir, queryRange)

// Verify the results
assert(matchingFiles != null, "Matching files array should not be null")
assert(matchingFiles.length > 0, s"Expected at least 1 matching file, but got ${matchingFiles.length}")
assert(matchingFiles.exists(_.contains(sourcePath.getName)), "The matching file should be the copied raster")

println(s"__CHECK__ selectFiles ${matchingFiles.length}")

