spatialJoinDJ.code:
import edu.ucr.cs.bdlab.beast._
import edu.ucr.cs.bdlab.beast.indexing.RSGrovePartitioner
import edu.ucr.cs.bdlab.beast.operations.SpatialJoin
import edu.ucr.cs.bdlab.beast.cg.SpatialJoinAlgorithms.ESJPredicate

// The Distributed Join (DJ) algorithm requires both datasets to be spatially partitioned.
// We use RSGrovePartitioner to ensure disjoint partitions and prevent duplicate matches.
val partitionedR1 = featuresRDD.spatialPartition(classOf[RSGrovePartitioner])
val partitionedR2 = featuresRDD.spatialPartition(classOf[RSGrovePartitioner])

// Execute the Distributed Join (DJ)
val joinedFeatures = SpatialJoin.spatialJoinDJ(
  partitionedR1, 
  partitionedR2, 
  ESJPredicate.Intersects
)

// Materialize the result
val count = joinedFeatures.count()
val r1Count = featuresRDD.count()

// A self-join with the Intersects predicate must yield at least as many pairs as there are features,
// since every feature intersects with itself.
assert(count >= r1Count, s"Self-join with Intersects should yield at least $r1Count pairs, but got $count")
println(s"__CHECK__ spatialJoinDJ $count")

