import edu.ucr.cs.bdlab.beast.operations.SpatialJoin
import edu.ucr.cs.bdlab.beast.cg.SpatialJoinAlgorithms.ESJPredicate

// Perform a self-join using the Partition-Based Spatial-Merge (PBSM) algorithm
val joinedRDD = SpatialJoin.spatialJoinPBSM(featuresRDD, featuresRDD, ESJPredicate.Intersects)

// Materialize the result to trigger the distributed join
val joinCount = joinedRDD.count()
val originalCount = featuresRDD.count()

// In a self-join with the Intersects predicate, every feature must at least intersect with itself.
// Therefore, the number of joined pairs must be greater than or equal to the original feature count.
assert(joinCount >= originalCount, s"Expected self-join count ($joinCount) to be >= original count ($originalCount)")

println(s"__CHECK__ spatialJoinPBSM $joinCount")

